import { Link } from "react-router-dom";

function Card(props) {

  let overlayColor = `rgba(${props.colors[3].join(',')}, 1.0)`
  let labelColor = `rgba(${props.colors[3].join(',')}, 0.15)`

  return (
    <div className="Card">
      <Link to={props.project.path}> 
        <img alt={props.project.name} src={props.project.thumbPath} style={{"width": "100%"}}/>
        <div className="overlay" style={{backgroundColor: overlayColor}}>
          <div className="overlay-text noClick">
            {props.project.description()}
          </div>
        </div>
        <div className="label">
          <div className="label-text" style={{backgroundColor: labelColor}}>
            {props.project.name}
          </div>
        </div>
      </Link>
    </div>
  );
}

export default Card;
